var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"F동. 실험 및 의료 시설.","JPN":"F棟。実験室兼医療施設。","ENG":"F Wing. Experimental and medical facilities.","TWN":"F樓，實驗及醫療設施。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"무슨 냉동고에 들어온 것 같군. 한기가 바늘처럼 슈트를 뚫고 들어올 정도야.","JPN":"まるで冷凍庫にいるみたいだな。冷気が針のようにスーツを突き刺して入ってくるぜ。","ENG":"It's like a freezer here. The cold is piercing through my suit.","TWN":"我們好像進入了某個冷凍庫。這裡的寒氣刺骨，透過防護服往皮膚裡鑽。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"전기톱 아가씬 괜찮아? 외투 한 벌 없는데 말이지.","JPN":"チェンソーンのお嬢ちゃんは大丈夫か？　そんな薄着でよ。","ENG":"You okay, chainsaw lady? You don't even have a coat on.","TWN":"電鋸小姐，你還好嗎？你連防護服都沒穿。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"으그그그… 추, 추운 건 별로 안 좋아하지만, 그-그-그래도 괜찮… 아요.","JPN":"あ゙あ゙あ゙あ゙……さ、寒いのは苦手ですけど、で、で、でも大丈夫ですぅ……","ENG":"Brrr... I-I'm not a fan of the cold, but I-I-I'm okay.","TWN":"哈、哈——啾，我不太喜歡寒冷，不、不、不過沒關係……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"쓸데없이 멋부리다 얼어 죽지 말고, 죽은 친구 슈트라도 빌려 입지 그래?","JPN":"強がって凍え死んだら元も子もないぞ。死んだ仲間のスーツでも借りたらどうだ？","ENG":"Instead of freezing to death, why not borrow our dead friend's suit?","TWN":"別因為嘴硬凍死在這裡，不如找死去的朋友借用下吧？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"아, 안 돼요. 슈… 슈트가 피에 잔뜩 젖어서…","JPN":"ダ、ダメです。だってス……スーツにすごく血がたくさん……","ENG":"Oh, no. Th-the suit is soaked in blood...","TWN":"不、不要。那些防……防護服已經被血浸濕了……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"저-저-전 피 냄새 맡으면… 못 참거든요.","JPN":"わ……わ……私は血の匂いを嗅ぐと……むずむずして……","ENG":"a-a-and I can't control myself... when I smell blood...","TWN":"我、我、我聞到血腥味……會控制不住自己。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"몸이 얼어붙는 와중에도 위생 관리라니, 대단한 정신력이구만.","JPN":"身体が凍りつきそうなのに清潔感の方が重要だなんて、見上げた精神力だぜ。","ENG":"You're concerned about hygiene when you're freezing your socks off? That's some mentality you got there.","TWN":"你這是愛乾淨過頭了吧？不過還真是精神可嘉。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"대장, 여긴 사람 흔적은 보이지 않는데.","JPN":"隊長、ここに人の影はないみたいだが。","ENG":"Captain, there are no signs of people here.","TWN":"隊長，這裡沒發現任何人的蹤跡。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"이 넓은 곳에서 무작정 숨바꼭질만 계속할 셈인가?","JPN":"こんな広い場所で手あたり次第探し続けるつもりか？","ENG":"Are we just going to continue playing hide-and-seek in this massive place?","TWN":"這麼大的地方，還要繼續和對方玩捉迷藏嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"F동에 있는 감시카메라들을 사용할 거야.","JPN":"F棟の監視カメラを利用する。","ENG":"We're going to use the surveillance cameras in F Wing.","TWN":"我去看下F樓的監控鏡頭。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그러니 내가 터미널을 복원하는 동안 당신들은 <color=#ffd34c>요람</color>을 설치해줘.","JPN":"私がターミナルの復旧にあたっている間、あなたたちは<color=#ffd34c>ゆりかご</color>を設置して。","ENG":"While I restore the terminal, you guys set up the <color=#ffd34c>cradle</color>.","TWN":"在我恢復終端時，你們去把<color=#ffd34c>搖籃</color>安裝好。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"그러지.","JPN":"了解。","ENG":"Got it.","TWN":"好吧。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"됐어.","JPN":"よし、できた。","ENG":"Done.","TWN":"好了。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"카메라가… 중앙 터미널 통제가 아니잖아? 전부 로컬에만 연결되어 있다고…?","JPN":"カメラが……中央ターミナルでコントロールできない？　全部ローカルにしか繋がっていないだと……？","ENG":"The cameras... They're not connected to the central terminal and are all just linked locally...?","TWN":"攝影機……不是中央終端控制的？竟然都是本地連接的……？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"구역별로 모니터룸을 나눠 관리하는 방식인가? 보안 때문인 것 같은데, 귀찮게 됐네.","JPN":"エリア別にモニタールームを分けて管理しているのか？　セキュリティー対策ってところか。厄介だな。","ENG":"Are the control rooms separate for each zone? It seems like it's for security reasons, but this is rather inconvenient.","TWN":"這是監控室分區管理的方法嗎？雖然安全，但很麻煩。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"음…? 이건?","JPN":"うん、これは……？","ENG":"Mm? This is...?","TWN":"唔……？這是？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"오브젝트 알파- 감응 성공. 공격성을 상실하는 부작용 발견. 폐기…/","JPN":"オブジェクトアルファ‐感応コンプリート。攻撃性が消失する副作用を発見。廃棄……/","ENG":"Object Alpha - Response successful. Side effect of losing aggression detected. Discarding.../","TWN":"對象1 - 感應成功。副作用為喪失攻擊性。報廢處理……/"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"\\n오브젝트 베타- 감응 성공. 감응 주체로부터 도망치는 부작용 발견. 폐기…/","JPN":"\\nオブジェクトベーター‐感応コンプリート。感応主体から逃げ出す副作用を発見。廃棄……/","ENG":"\\nObject Beta - Response successful. Side effect of fleeing from the responsive subject detected. Discarding.../","TWN":"\\n對象2 - 感應成功。副作用為逃離感應主體。報廢處理……/"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"\\n오브젝트 감마- 감응 실패. 코어 폭주로 인한 통제불능. 안정될 때까지 1급 격리실에서 동면조치 후 실험 재개…/","JPN":"\\nオブジェクトガンマ‐感応失敗。コアが暴走しコントロール不能に。安定化するまで1級隔離室にて冬眠措置を取り、その後実験再開……/","ENG":"\\nObject Gamma - Response failure. Loss of control due to the core meltdown. Initiating cryogenic suspension in Level 1 quarantine to resume experimentation after stabilization.../","TWN":"\\n對象3 - 感應失敗。因核心暴走導致失控。轉移至一級隔離室進行冬眠，待穩定後重新開始實驗……/"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"\\n기록 담당자, 이바나 드라고비치_ 프로젝트 고문 및 책임자, 에드윈 프리하트…/","JPN":"\\n記録責任者イヴァナ・ドラゴビッチ_プロジェクトアドバイザーおよびディレクターエッドウィン・プラハト……/","ENG":"\\nRecords Officer: Ivana Dragovich_ Project Consultant and Supervisor, Edwin Freeheart.../","TWN":"\\n檔案管理員，伊維娜·德拉戈維奇_專案顧問兼負責人，艾德溫·普立哈特……/"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"에드윈…?","JPN":"エッドウィン……？","ENG":"Edwin...?","TWN":"艾德溫……？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"윽?!","JPN":"うっ！？","ENG":"Kgh?!","TWN":"嗯？！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이런 곳에 대형종이…?","JPN":"大型種が、こんなところに……？","ENG":"A large C.O. in a place like this...?","TWN":"這種地方怎麼會有大型侵蝕體……？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"몰려온다!","JPN":"大量に来るぞ！","ENG":"Here they come!","TWN":"它們來了！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"젠장, 왜 항상 막다른 길목에서만 이런 일이 벌어지는 거야!","JPN":"くっそ、どうしていつも逃げ場のない所に限って、こんなことが起こるんだ！","ENG":"Dammit, why does this always happen at dead ends?!","TWN":"可惡，偏偏這裡是死巷！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"곧 <color=#ffd34c>요람</color>이 활성화될 거야! 게이트를 전부 봉쇄했으니 조금만 버텨!","JPN":"<color=#ffd34c>ゆりかご</color>の活性化まであともう少しだ！　ゲートはすべて封鎖したから、少しだけ持ちこたえろ！","ENG":"The <color=#ffd34c>cradle</color> will activate soon! We've sealed off all the gates, so just hold on a little longer!","TWN":"很快<color=#ffd34c>搖籃</color>就會啟動！所有的門都堵住了，再堅持一會下！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}}]`);export{e as default};